// Support both direct JSON and webhook body wrapper
const raw  = $input.first().json;
const body = raw.body || raw;

let resumeJson = body.resume_json;
let jdRaw = body.jd_raw || '';

// If resume_json arrived as a string (double-encoded), parse it
if (typeof resumeJson === 'string') {
  try { resumeJson = JSON.parse(resumeJson); } catch(e) {}
}

// Normalise jd_raw to string regardless of how it arrived
if (typeof jdRaw === 'object') {
  jdRaw = jdRaw.jd_raw || JSON.stringify(jdRaw);
}
jdRaw = String(jdRaw).trim();

if (!resumeJson) throw new Error('resume_json is required. Got: ' + typeof body.resume_json + ' keys: ' + Object.keys(body).join(','));
if (!jdRaw)      throw new Error('jd_raw is required');

const resumeStr = JSON.stringify(resumeJson, null, 2);

// Trim JD to a reasonable size
const jdTrimmed = jdRaw.slice(0, 8000);

const outputSchema = {
  tailored_resume: {
    contact:    { name: 'string', email: 'string', phone: 'string', linkedin: 'string', github: 'string' },
    summary:    'string — rewritten to mirror JD language and highlight candidate fit',
    skills:     [{ category: 'string', items: ['string — JD-matching skills listed first'] }],
    experience: [{ company: 'string', title: 'string', dates: 'string', bullets: ['string — strong verbs + JD keywords'] }],
    projects:   [{ name: 'string', tech: ['string'], bullets: ['string — relevance to JD highlighted'] }],
    education:  [{ institution: 'string', degree: 'string', dates: 'string', gpa: 'string' }]
  },
  matched_keywords: ['string — keywords from JD present or aligned in tailored resume'],
  ats_score: 'integer 0–100'
};

const prompt = `You are a professional resume optimization expert specializing in ATS optimization.

Tailor the candidate's resume to the job description and return a structured JSON response.

## CRITICAL RULES:
1. Only use facts from the candidate's resume. NEVER add skills, companies, titles, or metrics not already present.
2. You MAY rewrite bullets with stronger action verbs and JD keywords — only when the underlying fact supports it.
3. You MAY re-rank skills so JD-matching items appear first within each category.
4. You MAY rewrite the summary to emphasize the most relevant experience.
5. Never fabricate GPA, dates, certifications, or quantitative metrics.
6. Preserve ALL original experience, education, and project entries — do not drop any.
7. Return ONLY valid JSON. No markdown fences, no explanatory text.

## CANDIDATE RESUME (JSON):
${resumeStr}

## JOB DESCRIPTION:
---
${jdTrimmed}
---

## REQUIRED OUTPUT SCHEMA:
${JSON.stringify(outputSchema, null, 2)}

## ATS SCORE METHODOLOGY:
Count distinct JD keywords/phrases present in the tailored resume, estimate coverage as 0–100 integer.

Return the JSON object now:`;

return [{ json: { prompt } }];

const response = $input.first().json;

if (response.error) {
  throw new Error('Gemini API error: ' + JSON.stringify(response.error));
}

let rawText;
try {
  rawText = response.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Unexpected Gemini response: ' + JSON.stringify(response).slice(0, 300));
}

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('JSON parse failed: ' + e.message + ' | Raw: ' + rawText.slice(0, 200));
}

if (!parsed.tailored_resume || typeof parsed.tailored_resume !== 'object') {
  throw new Error('Gemini response missing tailored_resume key');
}

const tr = parsed.tailored_resume;
const normalised = {
  contact:    tr.contact    || { name: '', email: '', phone: '', linkedin: '', github: '' },
  summary:    tr.summary    || '',
  skills:     Array.isArray(tr.skills)     ? tr.skills     : [],
  experience: Array.isArray(tr.experience) ? tr.experience : [],
  projects:   Array.isArray(tr.projects)   ? tr.projects   : [],
  education:  Array.isArray(tr.education)  ? tr.education  : []
};

const matched = Array.isArray(parsed.matched_keywords) ? parsed.matched_keywords : [];
let score = parseInt(parsed.ats_score, 10);
if (isNaN(score)) score = 0;
score = Math.max(0, Math.min(100, score));

return [{ json: { tailored_resume: normalised, matched_keywords: matched, ats_score: score } }];
